     1→import { getPageBySlug, getAllPages, getAllPosts, getListingPosts, getSeriesData, getSeriesPosts, getSeriesAuthors, getAuthorSlug } from '@/lib/markdown';
     2→import { notFound } from 'next/navigation';
     3→import PostLayout from '@/layouts/PostLayout';
     4→import SimpleLayout from '@/layouts/SimpleLayout';
     5→import PostList from '@/components/PostList';
     6→import SeriesCatalog from '@/components/SeriesCatalog';
     7→import Pagination from '@/components/Pagination';
     8→import CoverImage from '@/components/CoverImage';
     9→import Link from 'next/link';
    10→import { Metadata } from 'next';
    11→import { siteConfig } from '../../../site.config';
    12→import { resolveLocale, t } from '@/lib/i18n';
    13→import PageHeader from '@/components/PageHeader';
    14→import { getPostsBasePath, getSeriesCustomPaths, getPostUrl } from '@/lib/urls';
    15→import RedirectPage from '@/components/RedirectPage';
    16→
    17→const POST_PAGE_SIZE = siteConfig.pagination.posts;
    18→const SERIES_PAGE_SIZE = siteConfig.pagination.series;
    19→
    20→/**
    21→ * Generates the static paths for all top-level pages at build time,
    22→ * plus any custom URL prefixes configured for posts or series.
    23→ */
    24→export async function generateStaticParams() {
    25→  const pages = getAllPages();
    26→  const params = pages.map((page) => ({ slug: page.slug }));
    27→
    28→  // Add custom posts basePath listing (e.g. /articles)
    29→  const basePath = getPostsBasePath();
    30→  if (basePath !== 'posts') {
    31→    params.push({ slug: basePath });
    32→  }
    33→
    34→  // Add series custom path listings (e.g. /weeklies)
    35→  for (const customPath of Object.values(getSeriesCustomPaths())) {
    36→    params.push({ slug: customPath });
    37→  }
    38→
    39→  // Add single-segment redirectFrom paths (e.g. /old-slug).
    40→  // Throws on any alias that collides with a reserved top-level slug or a
    41→  // duplicate alias across posts — strict build catches misconfiguration early.
    42→  const reservedSlugs = new Set([
    43→    ...pages.map(p => p.slug),
    44→    basePath,
    45→    ...Object.values(getSeriesCustomPaths()),
    46→    // Hardcoded top-level routes that have their own app/ directories
    47→    'posts', 'series', 'tags', 'authors', 'archive', 'books', 'flows', 'notes', 'search', 'page',
    48→  ]);
    49→  for (const post of getAllPosts()) {
    50→    for (const from of post.redirectFrom ?? []) {
    51→      const segments = from.split('/').filter(Boolean);
    52→      if (segments.length !== 1) continue;
    53→      if (from === getPostUrl(post)) continue;
    54→      const alias = segments[0];
    55→      if (reservedSlugs.has(alias)) {
    56→        throw new Error(
    57→          `[amytis] redirectFrom "${from}" in post "${post.slug}" conflicts with an existing top-level route or redirect alias.`
    58→        );
    59→      }
    60→      reservedSlugs.add(alias);
    61→      params.push({ slug: alias });
    62→    }
    63→  }
    64→
    65→  return params;
    66→}
    67→
    68→export const dynamicParams = false;
    69→
    70→export async function generateMetadata({ params }: { params: Promise<{ slug: string }> }): Promise<Metadata> {
    71→  const { slug: rawSlug } = await params;
    72→  const slug = decodeURIComponent(rawSlug);
    73→
    74→  // Custom posts basePath
    75→  const basePath = getPostsBasePath();
    76→  if (slug === basePath && basePath !== 'posts') {
    77→    return {
    78→      title: `${t('posts')} | ${resolveLocale(siteConfig.title)}`,
    79→      description: t('posts_description'),
    80→    };
    81→  }
    82→
    83→  // Series custom paths
    84→  const customPaths = getSeriesCustomPaths();
    85→  const matchedSeriesSlug = Object.entries(customPaths).find(([, path]) => path === slug)?.[0];
    86→  if (matchedSeriesSlug) {
    87→    const seriesData = getSeriesData(matchedSeriesSlug);
    88→    if (seriesData) {
    89→      return {
    90→        title: `${seriesData.title} - ${t('series')} | ${resolveLocale(siteConfig.title)}`,
    91→        description: seriesData.excerpt,
    92→      };
    93→    }
    94→  }
    95→
    96→  const page = getPageBySlug(slug);
    97→  if (page) {
    98→    return {
    99→      title: `${page.title} | ${resolveLocale(siteConfig.title)}`,
   100→      description: page.excerpt,
   101→    };
   102→  }
   103→
   104→  // Single-segment redirectFrom — only if no real page exists for this slug
   105→  const redirectPost = getAllPosts().find(p => p.redirectFrom?.includes(`/${slug}`));
   106→  if (redirectPost) {
   107→    return { title: redirectPost.title };
   108→  }
   109→
   110→  return { title: 'Page Not Found' };
   111→}
   112→
   113→export default async function Page({
   114→  params,
   115→}: {
   116→  params: Promise<{ slug: string }>;
   117→}) {
   118→  const { slug: rawSlug } = await params;
   119→  const slug = decodeURIComponent(rawSlug);
   120→
   121→  // Check if slug matches custom posts basePath
   122→  const basePath = getPostsBasePath();
   123→  if (slug === basePath && basePath !== 'posts') {
   124→    const allPosts = getListingPosts();
   125→    const totalPages = Math.ceil(allPosts.length / POST_PAGE_SIZE);
   126→    const posts = allPosts.slice(0, POST_PAGE_SIZE);
   127→
   128→    return (
   129→      <div className="layout-main">
   130→        <PageHeader
   131→          titleKey="posts"
   132→          subtitleKey="posts_subtitle"
   133→          subtitleParams={{ count: allPosts.length }}
   134→          className="mb-12"
   135→        />
   136→        <PostList posts={posts} />
   137→        {totalPages > 1 && (
   138→          <div className="mt-12">
   139→            <Pagination currentPage={1} totalPages={totalPages} basePath={`/${basePath}`} />
   140→          </div>
   141→        )}
   142→      </div>
   143→    );
   144→  }
   145→
   146→  // Check if slug matches a series custom path
   147→  const customPaths = getSeriesCustomPaths();
   148→  const matchedSeriesSlug = Object.entries(customPaths).find(([, path]) => path === slug)?.[0];
   149→  if (matchedSeriesSlug) {
   150→    const seriesData = getSeriesData(matchedSeriesSlug);
   151→    const allPosts = getSeriesPosts(matchedSeriesSlug);
   152→
   153→    if ((!seriesData && allPosts.length === 0) || (process.env.NODE_ENV === 'production' && seriesData?.draft)) {
   154→      notFound();
   155→    }
   156→
   157→    const totalPages = Math.ceil(allPosts.length / SERIES_PAGE_SIZE);
   158→    const posts = allPosts.slice(0, SERIES_PAGE_SIZE);
   159→
   160→    const title = seriesData?.title || matchedSeriesSlug.charAt(0).toUpperCase() + matchedSeriesSlug.slice(1);
   161→    const description = seriesData?.excerpt;
   162→    const coverImage = seriesData?.coverImage;
   163→
   164→    const explicitAuthors = getSeriesAuthors(matchedSeriesSlug);
   165→    let authors: string[];
   166→    if (explicitAuthors) {
   167→      authors = explicitAuthors;
   168→    } else if (allPosts.length > 0) {
   169→      const counts = new Map<string, number>();
   170→      for (const post of allPosts) {
   171→        for (const author of post.authors) {
   172→          counts.set(author, (counts.get(author) || 0) + 1);
   173→        }
   174→      }
   175→      authors = [...counts.entries()].sort((a, b) => b[1] - a[1]).map(([name]) => name);
   176→    } else {
   177→      authors = [];
   178→    }
